def is_octagonal(n):
    if n < 1:
        return False
    # Formula: x = (1 + sqrt(8n - 1)) / 4
    import math
    discriminant = 8 * n - 1
    if discriminant < 0:
        return False
    sqrt_disc = math.isqrt(discriminant)
    if sqrt_disc * sqrt_disc != discriminant:
        return False
    numerator = 1 + sqrt_disc
    if numerator % 4 != 0:
        return False
    return True

def is_octagonal(n: int) -> int:
    """
    Return the nth octagonal number.
    The nth octagonal number is given by the formula:
    O_n = n * (3n - 2)
    """
    if n < 1:
        raise ValueError("n must be a positive integer")
    return n * (3 * n - 2)

