def eulerian_num(n, m):
    """
    Compute the Eulerian number a(n, m), which counts the number of permutations of {1, ..., n}
    with exactly m descents.

    Uses the recurrence relation:
        a(n, m) = (n - m) * a(n - 1, m - 1) + (m + 1) * a(n - 1, m)
    with base cases:
        a(0, 0) = 1
        a(n, 0) = 1 for n >= 1
        a(n, n) = 0 for n >= 1

    Parameters:
        n (int): number of elements in the permutation
        m (int): number of descents in the permutation

    Returns:
        int: Eulerian number a(n, m)
    """
    if n == 0 and m == 0:
        return 1
    if m == 0:
        return 1
    if m >= n:
        return 0

    # Use memoization to avoid redundant calculations
    memo = {}

    def dp(i, j):
        if (i, j) in memo:
            return memo[(i, j)]
        if i == 0 and j == 0:
            result = 1
        elif j == 0:
            result = 1
        elif j >= i:
            result = 0
        else:
            result = (i - j) * dp(i - 1, j - 1) + (j + 1) * dp(i - 1, j)
        memo[(i, j)] = result
        return result

    return dp(n, m)
