def search(arr):
    """
    Find the element that appears only once in a sorted array where every other element appears exactly twice.

    Args:
        arr (list): A sorted list of integers where every element appears twice except one that appears once.

    Returns:
        int: The unique element that appears only once.
    """
    left, right = 0, len(arr) - 1

    while left < right:
        mid = (left + right) // 2

        # Check if mid is the unique element
        if mid == 0 or arr[mid - 1] != arr[mid]:
            if mid == len(arr) - 1 or arr[mid + 1] != arr[mid]:
                return arr[mid]

        # Determine which half to search based on parity of mid and its neighbors
        if mid % 2 == 0:
            if arr[mid] == arr[mid + 1]:
                left = mid + 1
            else:
                right = mid
        else:
            if arr[mid] == arr[mid - 1]:
                left = mid + 1
            else:
                right = mid

    # If the loop ends, the single element is at left
    return arr[left]
