def max_occurrences(lst):
    """
    Returns the item that appears most frequently in the input list.
    In case of a tie, returns the first item encountered with the maximum frequency.
    """
    if not lst:
        return None

    freq = {}
    for item in lst:
        freq[item] = freq.get(item, 0) + 1

    max_item = lst[0]
    max_count = freq[max_item]

    for item, count in freq.items():
        if count > max_count:
            max_item = item
            max_count = count

    return max_item
