import math

def find_solution(a, b, n):
    if a == 0 and b == 0:
        return None
    if a == 0:
        if n % b == 0:
            return (0, n // b)
        else:
            return None
    if b == 0:
        if n % a == 0:
            return (n // a, 0)
        else:
            return None

    # Extended Euclidean Algorithm to find x0, y0 such that a*x0 + b*y0 = gcd(a, b)
    def extended_gcd(a, b):
        if b == 0:
            return (a, 1, 0)
        else:
            g, x1, y1 = extended_gcd(b, a % b)
            x = y1
            y = x1 - (a // b) * y1
            return (g, x, y)

    g, x0, y0 = extended_gcd(a, b)

    if n % g != 0:
        return None

    # Scale the solution to match n
    x = x0 * (n // g)
    y = y0 * (n // g)
    return (x, y)
