    Returns True if `element` is the majority element in the sorted array `arr`.
    A majority element occurs more than n/2 times.
    """
    # Since the array is sorted, all occurrences of the element are contiguous.
    # Use binary search to find the first and last occurrence of the element.
    def find_first(arr, element):
        left, right = 0, len(arr) - 1
        first = -1
        while left <= right:
            mid = (left + right) // 2
            if arr[mid] == element:
                first = mid
                right = mid - 1
            elif arr[mid] < element:
                left = mid + 1
            else:
                right = mid - 1
        return first

    def find_last(arr, element):
        left, right = 0, len(arr) - 1
        last = -1
        while left <= right:
            mid = (left + right) // 2
            if arr[mid] == element:
                last = mid
                left = mid + 1
            elif arr[mid] < element:
                left = mid + 1
            else:
                right = mid - 1
        return last

    first_idx = find_first(arr, element)
    if first_idx == -1:
        return False  # Element not present in the array

    count = last_idx - first_idx + 1
    return count > n // 2

