def get_total_number_of_sequences(m, n):
    # dp[i][v] = number of valid sequences of length i ending with value v
    # We use a dictionary to avoid iterating over all values up to m
    # Initialize for sequences of length 1: any value from 1 to m is valid
    dp = {v: 1 for v in range(1, m + 1)}

    # Build sequences of length 2 to n
    for length in range(2, n + 1):
        new_dp = {}
        for prev_val, count in dp.items():
            # Next value must be at least 2 * prev_val and at most m
            start = 2 * prev_val
            if start <= m:
                for next_val in range(start, m + 1):
                    new_dp[next_val] = new_dp.get(next_val, 0) + count
        dp = new_dp

    # Sum counts of all valid sequences of length n
    total = sum(dp.values())
    return total
