    n = len(arr)
    if n == 0:
        return 0

    # dp_inc[i] = maximum sum of increasing subsequence ending at i
    dp_inc = [arr[0]] * n
    # dp_dec[i] = maximum sum of decreasing subsequence starting at i
    dp_dec = [arr[-1]] * n

    # Build increasing subsequences ending at each index
    for i in range(1, n):
        max_prev = arr[i]
        for j in range(i):
            if arr[j] < arr[i]:
                max_prev = max(max_prev, dp_inc[j] + arr[i])
        dp_inc[i] = max_prev

    # Build decreasing subsequences starting at each index
    for i in range(n - 2, -1, -1):
        max_next = arr[i]
        for j in range(i + 1, n):
            if arr[j] < arr[i]:
                max_next = max(max_next, dp_dec[j] + arr[i])
        dp_dec[i] = max_next

    # Find the best bitonic subsequence sum
    best = arr[0]
    for i in range(n):
        # Skip single-element subsequences by ensuring both parts are non-empty
        if i > 0 and i < n - 1:
            best = max(best, dp_inc[i] + dp_dec[i] - arr[i])
        else:
            best = max(best, dp_inc[i])

