def harmonic_sum(n):
    """
    Calculate the harmonic sum of n-1, i.e., sum_{k=1}^{n-1} 1/k.
    """
    if n <= 1:
        return 0.0
    total = 0.0
    for k in range(1, n):
        total += 1.0 / k
    return total

