import math

def newman_prime(n):
    """
    Returns the nth prime number that is a Newmann-Shanks-Williams prime.

    A Newmann-Shanks-Williams (NSW) prime is a prime number p such that
    p = k^2 + 1 for some integer k, and the Fibonacci number F_k is also prime.
    """
    def is_prime(num):
        if num < 2:
            return False
        if num == 2:
            return True
        if num % 2 == 0:
            return False
        for i in range(3, int(math.isqrt(num)) + 1, 2):
            if num % i == 0:
                return False
        return True

    def fib(n):
        # Fibonacci sequence: F(0)=0, F(1)=1, F(2)=1, ...
        if n <= 0:
            return 0
        elif n == 1 or n == 2:
            return 1
        a, b = 1, 1
        for _ in range(3, n + 1):
            a, b = b, a + b
        return b

    count = 0
    k = 2
    while True:
        p = k * k + 1
        if is_prime(p) and is_prime(fib(k)):
            count += 1
            if count == n:
                return p
        k += 1
