def bitwise_xor(tuples):
    """
    Perform bitwise XOR operation across two tuples element-wise.
    """
    if len(tuples) != 2:
        raise ValueError("Exactly two tuples are required for bitwise XOR operation.")

    a, b = tuples
    if len(a) != len(b):
        raise ValueError("Tuples must be of equal length for element-wise XOR.")

    result = []
    for x, y in zip(a, b):
        result.append(x ^ y)

    return tuple(result)
