def count_bidirectional(tuples):
    from collections import defaultdict
    count = defaultdict(int)
    for a, b in tuples:
        count[(a, b)] += 1
        count[(b, a)] += 1
    pairs = set()
    for (a, b), freq in count.items():
        if freq >= 2:
            pairs.add((a, b))
    return len(pairs)
