    result = []
    i = 0
    while i < len(s):
        j = i
        while j < len(s) and s[j].islower():
            j += 1
        if j == i:
            # Single lowercase character, skip it
            i += 1
        else:
            # Lowercase substring from i to j-1, skip it
            i = j
    return ''.join(result)
